#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[1005];
        scanf("%s", s);
        int sum = 0;
        for (int i = 0; s[i]; i++) {
            if (s[i] >= '0' && s[i] <= '9') {
                sum += s[i] - '0';
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

